randomNumber:
use strict;
use warnings;

# Generate a random floating-point number between 0.0 (inclusive) and 1.0 (exclusive)
my $random_float = rand();
print "Random float [0.0, 1.0): ${random_float}\n";

# Generate a random integer between 0 (inclusive) and max (exclusive)
my $max_exclusive = 101; # To get numbers up to 100
my $random_int_upto = int(rand($max_exclusive)); # int() truncates
print "Random integer [0-${max_exclusive}-1]: ${random_int_upto}\n";

# Generate a random integer within a specific range [min, max] (inclusive)
my $min_val = 1;
my $max_val = 100;
my $random_int_range = $min_val + int(rand($max_val - $min_val + 1));
print "Random integer [${min_val}-${max_val}]: ${random_int_range}\n";

# Select a random element from an array (@)
my @fruits = ("apple", "banana", "cherry");
if (@fruits) { # Check if array is not empty
    my $random_index = int(rand(@fruits)); # rand(@array) gives 0..size-1 index
    my $random_fruit = $fruits[$random_index];
    print "Random fruit: ${random_fruit}\n";
}

