fibonacci:
use strict;
use warnings;
use feature 'say'; # Use say instead of print for automatic newline (Perl 5.10+)
use bigint; # Automatically handle arbitrarily large integers

# Function to calculate the Nth Fibonacci number (0-indexed) iteratively
sub fibonacci {
    my ($n) = @_; # Get argument
    die "Input must be non-negative" if (!defined $n || $n < 0);

    return 0 if $n == 0;
    return 1 if $n == 1;

    my $a = 0;
    my $b = 1;

    for (my $i = 2; $i <= $n; $i++) {
        # Parallel assignment (list context) swaps values
        ($a, $b) = ($b, $a + $b);
    }
    return $b;
}

# Function to generate first 'count' Fibonacci numbers
sub generate_fib_sequence {
    my ($count) = @_; 
    die "Count must be non-negative" if (!defined $count || $count < 0);
    # Use map to apply fibonacci to the range 0 to count-1
    return [ map { fibonacci($_) } (0 .. $count - 1) ];
}

# Example Usage
my $n = 10;
say "Fibonacci number F(${n}): ", fibonacci($n);

my $num_terms = 15;
say "First ${num_terms} Fibonacci numbers:";
my $sequence_ref = generate_fib_sequence($num_terms);
# Dereference array reference for printing nicely
say "[", join(", ", @$sequence_ref), "]";

# Example with large number (handled by 'use bigint')
my $large_n = 90;
say "Fibonacci number F(${large_n}): ", fibonacci($large_n);

