use strict;
use warnings;
use feature 'say';
use bigint; # Handle large factorials automatically
# Optional: use List::Util 'reduce'; # For reduce example

# Function to calculate factorial N!

# Method 1: Iterative using a loop
sub factorial_loop {
    my ($n) = @_; 
    die "Factorial input must be non-negative" if (!defined $n || $n < 0);
    return 1 if $n == 0;

    my $result = 1;
    for my $i (1 .. $n) {
