primeCheck:
use strict;
use warnings;
use feature 'say';

# Function to check if a number is prime
sub is_prime {
    my ($n) = @_; 

    # Basic checks
    return 0 unless defined $n && $n =~ /^[0-9]+$/ && $n == int($n); # Basic integer check
    return 0 if $n <= 1;
    return 1 if $n <= 3;
    return 0 if $n % 2 == 0 || $n % 3 == 0;

    # Check factors from 5 upwards, stepping by 6
    my $limit = int(sqrt($n));
    my $i = 5;
    while ($i <= $limit) {
        return 0 if $n % $i == 0 || $n % ($i + 2) == 0;
        $i += 6;
    }
    return 1; # Return true (1) if no divisors found
}

# Example usage
my @numbers_to_check = (2, 3, 4, 17, 25, 29, 97, 100, 1, -5, 1_000_000_007);

foreach my $n (@numbers_to_check) {
    if (is_prime($n)) {
        say "${n} is prime.";
    } else {
        say "${n} is not prime.";
    }
}

readFile:
use strict;
use warnings;
use feature 'say';
use autodie; # Automatically checks open/close/read/write errors

my $file_path = "perl_read_test.txt";

# Create a dummy file for reading
eval {
    open my $fh_write, '>', $file_path; # Open for writing ('>')
    print $fh_write "Line 1 content from Perl.\n";
    print $fh_write "This is the second line.\n";
    print $fh_write "End.\n";
    close $fh_write;
    say "Created dummy file '${file_path}' for reading.";
};
if ($@) {
    warn "Error creating dummy file: $@";
    exit 1;
}

say "\n--- Reading file '${file_path}' ---";

# Check if file exists and is a plain file first
if (-f $file_path) { # -f checks for plain file

    # Method 1: Read line by line using while loop (memory efficient)
    say "\n--- Reading line by line ---";
    open my $fh_read, '<', $file_path; # Open for reading ('<') with lexical handle
    my $line_num = 1;
    while (my $line = <$fh_read>) { # Read line into $line
        chomp $line; # Remove trailing newline
        say "Line ${line_num}: ${line}";
        $line_num++;
    }
    close $fh_read;
    say "--- End of line-by-line read ---";


    # Method 2: Slurp entire file into a scalar
    say "\n--- Reading entire file (slurp) ---";
    open my $fh_slurp, '<', $file_path;
    my $content = do { local $/; <$fh_slurp> }; # Temporarily undef record separator
    close $fh_slurp;
    say "File content as single string:";
    print $content; # Use print to avoid extra newline
    say "--- End of slurp read ---";


     # Method 3: Read all lines into an array
     say "\n--- Reading into array ---";
     open my $fh_array, '<', $file_path;
     my @lines = <$fh_array>; # Read all lines in list context
     close $fh_array;
     chomp @lines; # Remove newlines from all elements
     say "Read ", scalar(@lines), " lines into array:";
     # print join("\n", @lines), "\n"; # Print array elements joined by newline


} else {
    warn "Error: File not found or is not a regular file: '${file_path}'";
}

# Clean up dummy file
unlink $file_path or warn "Could not delete dummy file '${file_path}': $!";
say "\nCleaned up dummy file '${file_path}'.";

writeFile:
use strict;
use warnings;
use feature 'say';
use autodie; # Automatically checks open/close/print errors

my $file_path = "output_perl.txt";
my @initial_lines = (
    "First line written by Perl.",
    "Second line using print."
);
my $line_to_append = "Third line, appended.";

# --- Write using open '>' (overwrites or creates) ---
say "--- Writing to '${file_path}' (overwrite) ---";
eval {
    open my $fh_write, '>', $file_path; # Open for writing, truncates/creates
    foreach my $line (@initial_lines) {
        print $fh_write "${line}\n"; # Print each line with newline
    }
    # print $fh_write join("\n", @initial_lines), "\n"; # Alternative: join then print
    close $fh_write;
    say "Successfully wrote ", scalar(@initial_lines), " lines.";
};
if ($@) {
    warn "Error writing to file '${file_path}': $@";
}


# --- Append using open '>>' ---
say "\n--- Appending to '${file_path}' ---";
eval {
    open my $fh_append, '>>', $file_path; # Open for appending
    print $fh_append "${line_to_append}\n";
    close $fh_append;
    say "Successfully appended content.";
};
if ($@) {
    warn "Error appending to file '${file_path}': $@";
}


# --- Display final content (by reading back) ---
say "\n--- Final content of '${file_path}': ---";
if (-f $file_path) {
     eval {
        open my $fh_read, '<', $file_path;
        while (my $line = <$fh_read>) {
            print $line; # Print line as is (includes newline)
        }
        close $fh_read;
     };
     if ($@) { warn "Error reading back file: $@"; }
} else {
    warn "File '${file_path}' not found for display.";
}

# Optional: Clean up
# unlink $file_path or warn "Could not delete '${file_path}': $!";

