dateTime:
use strict;
use warnings;
use feature 'say';
use POSIX qw(strftime); # Import strftime function for flexible formatting
# use Time::Piece; # CPAN module for easier object-oriented time (optional)

say "--- Current Date and Time ---";

# time() returns seconds since the epoch (integer)
my $epoch_seconds = time();
say "Seconds since epoch: ${epoch_seconds}";

# localtime() in list context returns components based on system's local timezone
# (sec, min, hour, mday, mon(0-11), year(since 1900), wday(0-6, Sun=0), yday(0-365), isdst)
my ($sec, $min, $hour, $mday, $mon, $year_since_1900, $wday, $yday, $isdst) = localtime($epoch_seconds);

# Adjust month and year
$mon += 1; # Month is 0-11, adjust to 1-12
my $year = $year_since_1900 + 1900; # Year is years since 1900

say "\n--- Components (localtime) ---";
say "Year: ${year}";
say "Month: ${mon}";
say "Day: ${mday}";
say "Hour: ${hour}";
say "Minute: ${min}";
say "Second: ${sec}";
say "DayOfWeek: ${wday} (0=Sun)";
say "DayOfYear: ${yday} (0-365)";
say "Is DST?: ${isdst}";


# gmtime() returns components based on UTC
