say "YYYY-MM-DD: ", strftime("%Y-%m-%d", localtime($epoch_seconds));
say "HH:MM:SS (24hr): ", strftime("%H:%M:%S", localtime($epoch_seconds));
say "Readable: ", strftime("%A, %B %d, %Y at %I:%M:%S %p %Z", localtime($epoch_seconds));


