maxInArray:
use strict;
use warnings;
use feature 'say';
use List::Util 'max'; # Import 'max' function from core module List::Util

# Example numeric array
my @numbers = (10, 5, 42, 17, 8, 99, 32, -5, 0);
say "Array: (", join(", ", @numbers), ")";

# Use List::Util::max
# Returns undef for an empty list
my $max_value = max @numbers;

if (defined $max_value) {
    say "Maximum value (List::Util::max): ${max_value}";
} else {
    say "Array is empty, cannot find maximum.";
}


# Finding the index of the maximum (more manual)
sub find_max_index {
    my @list = @_; 
    return undef unless @list; # Return undef if list is empty
    my $max_val = $list[0];
    my $max_idx = 0;
    for my $i (1 .. $#list) { # Loop from index 1 to last index
        if ($list[$i] > $max_val) {
            $max_val = $list[$i];
            $max_idx = $i;
        }
    }
    return $max_idx;
}
my $max_idx = find_max_index(@numbers);
say "Index of maximum value: ${max_idx}" if defined $max_idx;


say "\n--- Other Examples ---";

# Example string array (lexicographical maximum)
my @strings = ("apple", "banana", "zebra", "cherry");
say "String array: (", join(", ", @strings), ")";
say "Maximum value (lexicographical): ", max @strings;

# Example empty array
my @empty_array = ();
my $max_empty = max @empty_array; # Returns undef
if (!defined $max_empty) {
     say "Cannot find maximum in empty array (max returns undef).";
}

# Example with undef values (max usually ignores them, check docs)
my @with_undef = (10, undef, 50, 20);
say "Maximum value (with undef): ", max @with_undef; # Typically 50


# Manual max without List::Util
sub manual_max {
    my @list = @_; 
    return undef unless @list;
    my $current_max = shift @list; # Take first element
    foreach my $elem (@list) {
        # Basic numeric/string comparison works; undefs might cause warnings
        $current_max = $elem if defined $elem and $elem gt $current_max; # Use gt for general comparison
    }
    return $current_max;
}
say "\nMax value (manual): ", manual_max(@numbers);
